// @title           TAP Education Backend API
// @version         1.0
// @description     TAP Education Backend 服务 API 文档
// @description     提供存储管理、镜像管理和开发机管理功能

// @contact.name   API Support
// @contact.url    http://www.example.com/support
// @contact.email  support@example.com

// @license.name  Apache 2.0
// @license.url   http://www.apache.org/licenses/LICENSE-2.0.html

// @host      localhost:8080
// @BasePath  /api/v1

// @securityDefinitions.apikey BearerAuth
// @in header
// @name Authorization
// @description Bearer Token 认证，格式: Bearer {token}。注意：当认证被禁用时，此安全要求不适用。

package main

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/spf13/cobra"
	"go.uber.org/zap"

	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/config"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/handler"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/logger"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/middleware"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/service/resource"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/pkg/auth"
)

var (
	configPath string
	port       int
)

var rootCmd = &cobra.Command{
	Use:   "tap-edu-backend",
	Short: "TAP Education Backend Service",
	Long:  "A backend service for TAP Education platform with storage, image, and dev machine management",
	RunE:  runServer,
}

func init() {
	rootCmd.Flags().StringVarP(&configPath, "config", "c", "config.yaml", "config file path")
	rootCmd.Flags().IntVarP(&port, "port", "p", 8080, "server port")
}

func runServer(cmd *cobra.Command, args []string) error {
	// 加载配置
	cfg, err := config.Load(configPath)
	if err != nil {
		return fmt.Errorf("failed to load config: %w", err)
	}

	// 初始化GPU配置
	resource.InitGPUConfig(cfg.Resources.GPUTypes)

	// 初始化日志
	log, err := logger.New(cfg.Log)
	if err != nil {
		return fmt.Errorf("failed to init logger: %w", err)
	}
	defer func() { _ = log.Sync() }()

	// 初始化认证
	authService := auth.NewService(cfg.Auth, log)

	// 初始化中间件
	authMiddleware := middleware.NewAuthMiddleware(authService, &cfg.Auth)
	logMiddleware := middleware.NewLogMiddleware(log)
	requestParamsMiddleware := middleware.NewRequestParamsMiddleware(log, &cfg.Log)

	// 设置 Gin 模式
	if cfg.Server.Mode == "release" {
		gin.SetMode(gin.ReleaseMode)
	}

	// 创建 Gin 引擎
	r := gin.New()
	r.Use(logMiddleware.Logger())
	r.Use(requestParamsMiddleware.PrintParams())
	r.Use(gin.Recovery())

	// 注册路由
	handler.RegisterRoutes(r, authMiddleware, authService, log, cfg)

	// 创建 HTTP 服务器
	srv := &http.Server{
		Addr:    fmt.Sprintf(":%d", port),
		Handler: r,
	}

	// 启动服务器
	go func() {
		log.Info("Starting server", zap.Int("port", port))
		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Fatal("Failed to start server", zap.Error(err))
		}
	}()

	// 优雅关闭
	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	log.Info("Shutting down server...")
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := srv.Shutdown(ctx); err != nil {
		log.Error("Server forced to shutdown", zap.Error(err))
		return err
	}

	log.Info("Server exited")
	return nil
}

func main() {
	if err := rootCmd.Execute(); err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
}

