package config

import (
	"fmt"
	"os"

	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/service/resource"
	"github.com/spf13/viper"
)

type Config struct {
	Server        ServerConfig        `mapstructure:"server"`
	Log           LogConfig           `mapstructure:"log"`
	Auth          AuthConfig          `mapstructure:"auth"`
	S3            S3Config            `mapstructure:"s3"`
	Harbor        HarborConfig        `mapstructure:"harbor"`
	K8s           K8sConfig           `mapstructure:"k8s"`
	TDSC          TDSCConfig          `mapstructure:"tdsc"`
	Resources     ResourcesConfig     `mapstructure:"resources"`
	InitContainer InitContainerConfig `mapstructure:"initContainer"`
}

type ServerConfig struct {
	Mode string `mapstructure:"mode"`
}

type LogConfig struct {
	Level              string `mapstructure:"level"`
	OutputPath         string `mapstructure:"outputPath"`
	PrintRequestParams bool   `mapstructure:"printRequestParams"` // 是否打印请求参数
	SkipFileOperations bool   `mapstructure:"skipFileOperations"` // 是否跳过文件上传/下载请求
}

type AuthConfig struct {
	Enabled   bool       `mapstructure:"enabled"`  // 是否启用认证
	AuthType  string     `mapstructure:"authType"` // 认证类型: "jwt" 或 "basic_auth"
	JWTSecret string     `mapstructure:"jwtSecret"`
	TokenTTL  int        `mapstructure:"tokenTtl"` // 秒
	Users     []UserInfo `mapstructure:"users"`    // 预设用户列表
}

type UserInfo struct {
	Username string `mapstructure:"username"`
	Password string `mapstructure:"password"`
	UserID   string `mapstructure:"userId"` // 可选，默认使用 username
}

type S3Config struct {
	Endpoint  string `mapstructure:"endpoint"`
	AccessKey string `mapstructure:"accessKey"`
	SecretKey string `mapstructure:"secretKey"`
	Bucket    string `mapstructure:"bucket"`
	Region    string `mapstructure:"region"`
}

type HarborConfig struct {
	URL      string `mapstructure:"url"`
	Domain   string `mapstructure:"domain"`
	Username string `mapstructure:"username"`
	Password string `mapstructure:"password"`
}

type K8sConfig struct {
	Kubeconfig string `mapstructure:"kubeconfig"`
	Namespace  string `mapstructure:"namespace"`
}

type TDSCConfig struct {
	Vol string `mapstructure:"vol"`
	URL string `mapstructure:"url"`
}

type ResourcesConfig struct {
	GPUTypes []resource.GPUType `mapstructure:"gpuTypes"`
}

type InitContainerConfig struct {
	Image string `mapstructure:"image"`
}

func Load(path string) (*Config, error) {
	viper.SetConfigFile(path)
	viper.SetConfigType("yaml")

	// 设置默认值
	viper.SetDefault("server.mode", "debug")
	viper.SetDefault("log.level", "info")
	viper.SetDefault("log.outputPath", "stdout")
	viper.SetDefault("log.printRequestParams", false)
	viper.SetDefault("log.skipFileOperations", true)
	viper.SetDefault("auth.tokenTtl", 3600)
	viper.SetDefault("auth.authType", "jwt")
	viper.SetDefault("auth.authType", "jwt")
	viper.SetDefault("k8s.namespace", "default")
	viper.SetDefault("initContainer.image", "gz01-srdart.srdcloud.cn/tdp-paas/tdp_paas-tap-snapshot-docker-local/dev-bootstrap:v1.0.1-rc2")

	// 允许从环境变量读取
	viper.AutomaticEnv()

	if err := viper.ReadInConfig(); err != nil {
		if _, ok := err.(viper.ConfigFileNotFoundError); !ok {
			return nil, fmt.Errorf("error reading config file: %w", err)
		}
		// 配置文件不存在时使用默认值
	}

	var cfg Config
	if err := viper.Unmarshal(&cfg); err != nil {
		return nil, fmt.Errorf("error unmarshaling config: %w", err)
	}

	// 设置认证开关的默认值（如果配置文件中没有设置）
	if !viper.IsSet("auth.enabled") {
		if cfg.Server.Mode == "debug" {
			cfg.Auth.Enabled = false
		} else {
			cfg.Auth.Enabled = true
		}
	}

	// 从环境变量覆盖敏感信息
	if jwtSecret := os.Getenv("JWT_SECRET"); jwtSecret != "" {
		cfg.Auth.JWTSecret = jwtSecret
	}
	if s3Key := os.Getenv("S3_ACCESS_KEY"); s3Key != "" {
		cfg.S3.AccessKey = s3Key
	}
	if s3Secret := os.Getenv("S3_SECRET_KEY"); s3Secret != "" {
		cfg.S3.SecretKey = s3Secret
	}
	if harborPass := os.Getenv("HARBOR_PASSWORD"); harborPass != "" {
		cfg.Harbor.Password = harborPass
	}
	if authEnabled := os.Getenv("AUTH_ENABLED"); authEnabled != "" {
		if authEnabled == "true" {
			cfg.Auth.Enabled = true
		} else if authEnabled == "false" {
			cfg.Auth.Enabled = false
		}
	}

	// 验证认证类型
	if cfg.Auth.Enabled && cfg.Auth.AuthType != "jwt" && cfg.Auth.AuthType != "basic_auth" {
		return nil, fmt.Errorf("invalid auth_type: %s, must be 'jwt' or 'basic_auth'", cfg.Auth.AuthType)
	}

	return &cfg, nil
}

