	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

// PVManager PersistentVolume 资源管理接口
type PVManager interface {
	// CreatePV 创建 PV
	CreatePV(ctx context.Context, pv *corev1.PersistentVolume) error
	// UpdatePV 更新 PV
	UpdatePV(ctx context.Context, pv *corev1.PersistentVolume) error
	// DeletePV 删除 PV
	DeletePV(ctx context.Context, name string) error
	// GetPV 获取 PV 信息
	GetPV(ctx context.Context, name string) (*corev1.PersistentVolume, error)
	// ListPVs 列出 PV
	ListPVs(ctx context.Context) ([]*corev1.PersistentVolume, error)
}

func (c *client) CreatePV(ctx context.Context, pv *corev1.PersistentVolume) error {
	_, err := c.clientset.CoreV1().PersistentVolumes().Create(ctx, pv, metav1.CreateOptions{})
	return err
}

func (c *client) UpdatePV(ctx context.Context, pv *corev1.PersistentVolume) error {
	oldPV, err := c.clientset.CoreV1().PersistentVolumes().Get(ctx, pv.Name, metav1.GetOptions{})
	if err != nil {
		return err
	}
	pv.ResourceVersion = oldPV.ResourceVersion
	_, err = c.clientset.CoreV1().PersistentVolumes().Update(ctx, pv, metav1.UpdateOptions{})
	return err
}

func (c *client) DeletePV(ctx context.Context, name string) error {
	return c.clientset.CoreV1().PersistentVolumes().Delete(ctx, name, metav1.DeleteOptions{})
}

func (c *client) GetPV(ctx context.Context, name string) (*corev1.PersistentVolume, error) {
	return c.clientset.CoreV1().PersistentVolumes().Get(ctx, name, metav1.GetOptions{})
}

func (c *client) ListPVs(ctx context.Context) ([]*corev1.PersistentVolume, error) {
	pvList, err := c.clientset.CoreV1().PersistentVolumes().List(ctx, metav1.ListOptions{})
	if err != nil {
		return nil, err
	}

	var pvs []*corev1.PersistentVolume
	for i := range pvList.Items {
		pvs = append(pvs, &pvList.Items[i])
	}
	return pvs, nil
}

