}

func (c *client) CreatePVC(ctx context.Context, pvc *corev1.PersistentVolumeClaim) error {
	_, err := c.clientset.CoreV1().PersistentVolumeClaims(pvc.Namespace).Create(ctx, pvc, metav1.CreateOptions{})
	return err
}

func (c *client) UpdatePVC(ctx context.Context, pvc *corev1.PersistentVolumeClaim) error {
	oldPVC, err := c.clientset.CoreV1().PersistentVolumeClaims(pvc.Namespace).Get(ctx, pvc.Name, metav1.GetOptions{})
	if err != nil {
		return err
	}
	pvc.ResourceVersion = oldPVC.ResourceVersion
	_, err = c.clientset.CoreV1().PersistentVolumeClaims(pvc.Namespace).Update(ctx, pvc, metav1.UpdateOptions{})
	return err
}

func (c *client) DeletePVC(ctx context.Context, namespace, name string) error {
	return c.clientset.CoreV1().PersistentVolumeClaims(namespace).Delete(ctx, name, metav1.DeleteOptions{})
}

func (c *client) GetPVC(ctx context.Context, namespace, name string) (*corev1.PersistentVolumeClaim, error) {
	return c.clientset.CoreV1().PersistentVolumeClaims(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *client) ListPVCs(ctx context.Context, namespace string) ([]*corev1.PersistentVolumeClaim, error) {
	if namespace == "" {
		namespace = c.namespace
	}
	pvcList, err := c.clientset.CoreV1().PersistentVolumeClaims(namespace).List(ctx, metav1.ListOptions{})
	if err != nil {
		return nil, err
	}

	var pvcs []*corev1.PersistentVolumeClaim
	for i := range pvcList.Items {
		pvcs = append(pvcs, &pvcList.Items[i])
	}
	return pvcs, nil
}

