   488→
   489→// generateDevMachineIngress 生成开发机 Ingress
   490→func generateDevMachineIngress(request *devmachinemodel.CreateDevmachineRequest) *networkingv1.Ingress {
   491→	webIDE := request.WebIDE
   492→	if webIDE == "" {
   493→		webIDE = devmachinemodel.WebIDEJupyter
   494→	}
   495→
   496→	if webIDE == devmachinemodel.WebIDEVSCode {
