// BuildResourceRequirements 构建资源请求和限制
func BuildResourceRequirements(cpu, memory, gpu, gpuName string) corev1.ResourceRequirements {
	requests := corev1.ResourceList{}
	limits := corev1.ResourceList{}

	// 设置 CPU 请求
	if cpu != "" {
		cpuQuantity, err := resource.ParseQuantity(cpu + "") // 用户传入的数值，单位为核
		if err == nil {
			requests[corev1.ResourceCPU] = cpuQuantity
			limits[corev1.ResourceCPU] = cpuQuantity
		}
	}

	// 设置内存请求
	if memory != "" {
		memoryQuantity, err := resource.ParseQuantity(memory + "Gi") // 用户传入的数值，单位为Gi
		if err == nil {
			requests[corev1.ResourceMemory] = memoryQuantity
			limits[corev1.ResourceMemory] = memoryQuantity
		}
	}

	// 设置 GPU 请求
	if gpu != "" && gpuName != "" {
		gpuQuantity, err := resource.ParseQuantity(gpu) // GPU 数量
		if err == nil {
			// 检查 GPU 是否为虚拟化类型
			if resourcesvc.IsGPUResource(gpuName) && resourcesvc.GetGPUType(gpuName) == resourcesvc.GPUCardTypeVirtual {
				// 如果是虚拟化 GPU，需要特殊处理
				requests[corev1.ResourceName(gpuName)] = gpuQuantity
				limits[corev1.ResourceName(gpuName)] = gpuQuantity
				//

			} else {
				// 如果是整卡 GPU，直接设置
				requests[corev1.ResourceName(gpuName)] = gpuQuantity
				limits[corev1.ResourceName(gpuName)] = gpuQuantity
			}
		}
	}

	return corev1.ResourceRequirements{
		Requests: requests,
		Limits:   limits,
	}
}

