   504→// generateVSCodeIngress 生成 VSCode Ingress
   505→func generateVSCodeIngress(request *devmachinemodel.CreateDevmachineRequest) *networkingv1.Ingress {
   506→	labels := generateLabels(request.Namespace, request.Name, request.Labels)
   507→	port := getServicePort(devmachinemodel.WebIDEVSCode)
   508→	basePath := buildIngressPath(request.Namespace, request.Name)
   509→	path := fmt.Sprintf("%s(/|$)(.*)", basePath)
   510→
   511→	annotations := defaultAnnotations
   512→	annotations[devmachinemodel.RewriteTarget] = "/$2"
   513→
   514→	ingress := &networkingv1.Ingress{
   515→		ObjectMeta: metav1.ObjectMeta{
   516→			Name:        request.Name + ingressSuffix,
   517→			Namespace:   request.Namespace,
   518→			Labels:      labels,
   519→			Annotations: annotations,
   520→		},
   521→		Spec: buildIngressSpec(request.Name+serviceSuffix, path, port),
   522→	}
   523→
   524→	return ingress
