   366→// buildSharedVolumes 根据 storage 列表构建共享卷（去重，最多 2 个）
   367→// ReadOnly=false 的 storage 共用 shared-rw-volume
   368→// ReadOnly=true  的 storage 共用 shared-ro-volume
   369→func buildSharedVolumes(storages []devmachinemodel.Storage) []corev1.Volume {
   370→	if len(storages) == 0 {
   371→		return nil
   372→	}
   373→
   374→	volumes := make([]corev1.Volume, 0, 2)
   375→	hasRW, hasRO := false, false
   376→
   377→	for _, s := range storages {
   378→		if !s.ReadOnly && !hasRW {
   379→			hasRW = true
   380→			volumes = append(volumes, corev1.Volume{
   381→				Name: SharedRWVolumeName,
   382→				VolumeSource: corev1.VolumeSource{
   383→					PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
   384→						ClaimName: SharedRWPVCName,
   385→					},
   386→				},
   387→			})
   388→		}
   389→		if s.ReadOnly && !hasRO {
   390→			hasRO = true
   391→			volumes = append(volumes, corev1.Volume{
   392→				Name: SharedROVolumeName,
   393→				VolumeSource: corev1.VolumeSource{
   394→					PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
   395→						ClaimName: SharedROPVCName,
   396→						ReadOnly:  true,
   397→					},
   398→				},
   399→			})
   400→		}
   401→	}
   402→
   403→	return volumes
   404→}
   405→
   406→// buildSharedVolumeMounts 构建共享卷挂载列表（每条 storage 独立挂载，subPath 隔离）
   407→func buildSharedVolumeMounts(storages []devmachinemodel.Storage) []corev1.VolumeMount {
   408→	if len(storages) == 0 {
   409→		return nil
   410→	}
   411→
   412→	mounts := make([]corev1.VolumeMount, 0, len(storages))
   413→	for _, s := range storages {
   414→		volName := SharedRWVolumeName
   415→		if s.ReadOnly {
   416→			volName = SharedROVolumeName
   417→		}
   418→		mounts = append(mounts, corev1.VolumeMount{
   419→			Name:      volName,
   420→			MountPath: s.MountPath,
   421→			SubPath:   s.StoragePath,
   422→			ReadOnly:  s.ReadOnly,
   423→		})
   424→	}
   425→
   426→	return mounts
   427→}
