   493→		webIDE = devmachinemodel.WebIDEJupyter
   494→	}
   495→
   496→	if webIDE == devmachinemodel.WebIDEVSCode {
   497→		return generateVSCodeIngress(request)
   498→	}
   499→	ing := generateJupyterIngress(request)
   500→	log.Infof("finish to create devmachine ingress: %s", util.JsonOutPut(ing))
