   288→// buildSharedPV 构建共享 PersistentVolume
   289→// 使用集群级别共享 PV，ReclaimPolicy 为 Retain（区别于旧的 Delete）
   290→func buildSharedPV(name, subPath string, readOnly bool) *corev1.PersistentVolume {
   291→	configMutex.RLock()
   292→	defer configMutex.RUnlock()
   293→
   294→	accessMode := corev1.ReadWriteMany
