   296→		accessMode = corev1.ReadOnlyMany
   297→	}
   298→
   299→	volumeMode := corev1.PersistentVolumeFilesystem
   300→	pv := &corev1.PersistentVolume{
   301→		ObjectMeta: metav1.ObjectMeta{
   302→			Name: name,
   303→		},
   304→		Spec: corev1.PersistentVolumeSpec{
   305→			Capacity: corev1.ResourceList{
   306→				corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
   307→			},
   308→			VolumeMode:  &volumeMode,
   309→			AccessModes: []corev1.PersistentVolumeAccessMode{accessMode},
   310→			PersistentVolumeReclaimPolicy: corev1.PersistentVolumeReclaimRetain,
   311→			PersistentVolumeSource: corev1.PersistentVolumeSource{
   312→				CSI: &corev1.CSIPersistentVolumeSource{
   313→					Driver: csiConfig.Driver,
   314→					FSType: "juicefs",
   315→					NodePublishSecretRef: &corev1.SecretReference{
   316→						Name:      csiConfig.SecretName,
   317→						Namespace: csiConfig.SecretNamespace,
   318→					},
   319→					VolumeHandle:     name,
   320→					VolumeAttributes: map[string]string{},
   321→				},
   322→			},
   323→		},
   324→	}
   325→
   326→	if csiConfig.MountOptions != nil {
   327→		pv.Spec.MountOptions = csiConfig.MountOptions
   328→	}
   329→	for k, v := range csiConfig.Parameters {
   330→		pv.Spec.CSI.VolumeAttributes[k] = v
   331→	}
   332→	if subPath != "" {
   333→		pv.Spec.CSI.VolumeAttributes["subPath"] = subPath
   334→	}
   335→
   336→	return pv
