   126→	// 3. 创建 Deployment
   127→	deployment := generateDevMachineDeployment(request, s.config.InitContainer.Image)
   128→	if err := s.k8sClient.CreateDeployment(ctx, deployment); err != nil {
   129→		return nil, NewResourceError("Deployment", request.Name, "create", err)
