   260→func (s *service) GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error) {
   261→	// 验证请求参数
   262→	if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
   263→		return nil, NewValidationError("devmachine", name, err)
   264→	}
   265→
   266→	// 获取 Deployment 信息
   267→	deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
   268→	if err != nil {
   269→		return nil, NewResourceError("Deployment", name, "get", err)
   270→	}
   271→
   272→	// 获取 Service 信息
   273→	service, err := s.k8sClient.GetService(ctx, namespace, name+serviceSuffix)
   274→	if err != nil {
   275→		return nil, NewResourceError("Service", name+serviceSuffix, "get", err)
   276→	}
   277→
   278→	// 获取 Ingress 信息
   279→	ingress, err := s.k8sClient.GetIngress(ctx, namespace, name+ingressSuffix)
   280→	if err != nil {
   281→		return nil, NewResourceError("Ingress", name+ingressSuffix, "get", err)
   282→	}
   283→
   284→	if deployment == nil || service == nil || ingress == nil {
   285→		return nil, fmt.Errorf("deployment or service or ingress not found")
   286→	}
   287→
   288→	// 获取与Deployment关联的存储信息
   289→	var storage []devmachinemodel.Storage
   290→
   291→	// 从Deployment的Pod模板中获取卷信息
   292→	volumes := deployment.Spec.Template.Spec.Volumes
   293→	for _, volume := range volumes {
   294→		// 检查卷是否是PVC类型的
   295→		if volume.PersistentVolumeClaim != nil {
   296→			pvcName := volume.PersistentVolumeClaim.ClaimName
   297→
   298→			// 获取具体的PVC信息
   299→			pvc, err := s.k8sClient.GetPVC(ctx, namespace, pvcName)
   300→			if err != nil || pvc == nil {
   301→				continue
   302→			}
   303→
   304→			// 检查PVC是否属于当前开发机
   305→			if IsPVCBelongsToDevmachine(pvc.Name, namespace, name) {
   306→				// 从PVC获取挂载路径
   307→				mountPath := GetMountPathForPVCByName(pvcName)
   308→
   309→				// 从PV中获取存储路径
   310→				if pvc.Spec.VolumeName != "" {
   311→					pv, err := s.k8sClient.GetPV(ctx, pvc.Spec.VolumeName)
   312→					if err == nil && pv != nil {
   313→						// 从 PV 的 VolumeAttributes 中获取 subPath
   314→						if juicefsSubPath, exists := pv.Spec.CSI.VolumeAttributes["subPath"]; exists {
   315→							storage = append(storage, devmachinemodel.Storage{
   316→								MountPath:   mountPath,
   317→								StoragePath: juicefsSubPath,
   318→							})
   319→						}
   320→					}
   321→				}
   322→			}
   323→		}
   324→	}
   325→
   326→	// 提取 GPU 信息
   327→	gpu := "0"
   328→	gpuName := ""
   329→	if len(deployment.Spec.Template.Spec.Containers) > 0 {
   330→		container := deployment.Spec.Template.Spec.Containers[0]
   331→		if gpuResource, exists := container.Resources.Requests["hygon.com/dcu"]; exists {
   332→			gpu = gpuResource.String()
   333→			gpuName = "hygon.com/dcu"
   334→		} else if gpuResource, exists := container.Resources.Requests["nvidia.com/gpu"]; exists {
   335→			gpu = gpuResource.String()
   336→			gpuName = "nvidia.com/gpu"
   337→		}
   338→	}
   339→
   340→	// 获取 WebIDE 类型
   341→	webIDE := GetWebIDEType(deployment)
   342→
   343→	// 构建响应
   344→	response := &devmachinemodel.GetDevmachineResponse{
   345→		Devmachine: devmachinemodel.Devmachine{
   346→			Namespace:   deployment.Namespace,
   347→			Name:        deployment.Name,
   348→			QueueName:   deployment.Spec.Template.Annotations[volcanoQueueName],
   349→			ImageName:   deployment.Spec.Template.Spec.Containers[0].Image,
   350→			CPU:         deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Cpu().String(),
   351→			Memory:      deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Memory().String(),
   352→			GPU:         gpu,
   353→			GPUName:     gpuName,
   354→			WebIDE:      webIDE,
   355→			WebUrl:      fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(namespace, name)),
   356→			Storage:     storage,
   357→			Annotations: deployment.Annotations,
   358→			Labels:      deployment.Labels,
   359→			Status:      getStatusFromDeployment(deployment),
   360→		},
   361→	}
   362→
   363→	return response, nil
   364→}
