   366→// getStatusFromDeployment 从Deployment获取状态
   367→// TODO: 添加pod级别的状态判断
   368→func getStatusFromDeployment(deployment *appsv1.Deployment) string {
   369→	if deployment.Status.ReadyReplicas > 0 {
   370→		return "running"
   371→	}
   372→	if deployment.Status.Replicas == 0 {
   373→		return "stopped"
   374→	}
   375→	return "pending"
   376→}
