   378→func (s *service) ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error) {
   379→	// 如果没有指定任何devmachine，则返回空列表
   380→	if len(devmachines) == 0 {
   381→		return []devmachinemodel.Devmachine{}, nil
   382→	}
   383→
   384→	// 初始化结果切片
   385→	results := make([]devmachinemodel.Devmachine, len(devmachines))
   386→	errors := make([]error, len(devmachines))
   387→
   388→	// 定义工作函数
   389→	workerFunc := func(piece int) {
   390→		// 获取指定的devmachine
   391→		devmachine := devmachines[piece]
   392→		// 调用GetDevmachine获取详细信息
   393→		result, err := s.GetDevmachine(ctx, devmachine.Namespace, devmachine.Name)
   394→		if err != nil {
   395→			errors[piece] = err
   396→		} else {
   397→			results[piece] = result.Devmachine
   398→		}
   399→	}
   400→
   401→	// 使用workqueue.ParallelizeUntil进行并行处理
   402→	// 限制最大并发数以避免对k8s API服务器造成过大压力
   403→	maxWorkers := 10
   404→	workqueue.ParallelizeUntil(ctx, maxWorkers, len(devmachines), workerFunc)
   405→
   406→	// 收集成功的结果
   407→	var successfulResults []devmachinemodel.Devmachine
   408→	for i, err := range errors {
   409→		if err == nil {
   410→			successfulResults = append(successfulResults, results[i])
   411→		} else {
   412→			log.Printf("warning: failed to get devmachine %s/%s: %v", devmachines[i].Namespace, devmachines[i].Name, err)
   413→		}
   414→	}
   415→
   416→	return successfulResults, nil
   417→}
