   231→func (s *service) GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error) {
   232→	// 验证请求参数
   233→	if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
   234→		return nil, NewValidationError("devmachine", name, err)
   235→	}
   236→
   237→	// 获取 Deployment 信息
   238→	deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
   239→	if err != nil {
   240→		return nil, NewResourceError("Deployment", name, "get", err)
   241→	}
   242→
   243→	// 获取 Service 信息
   244→	service, err := s.k8sClient.GetService(ctx, namespace, name+serviceSuffix)
   245→	if err != nil {
   246→		return nil, NewResourceError("Service", name+serviceSuffix, "get", err)
   247→	}
   248→
   249→	// 获取 Ingress 信息
   250→	ingress, err := s.k8sClient.GetIngress(ctx, namespace, name+ingressSuffix)
   251→	if err != nil {
   252→		return nil, NewResourceError("Ingress", name+ingressSuffix, "get", err)
   253→	}
   254→
   255→	if deployment == nil || service == nil || ingress == nil {
   256→		return nil, fmt.Errorf("deployment or service or ingress not found")
   257→	}
   258→
   259→	// 获取与Deployment关联的存储信息（从 volumeMounts 的 subPath 读取，共享PVC模式）
   260→	var storage []devmachinemodel.Storage
   261→	if len(deployment.Spec.Template.Spec.Containers) > 0 {
   262→		container := deployment.Spec.Template.Spec.Containers[0]
   263→		for _, vm := range container.VolumeMounts {
   264→			if vm.Name == SharedRWVolumeName || vm.Name == SharedROVolumeName {
   265→				storage = append(storage, devmachinemodel.Storage{
   266→					MountPath:   vm.MountPath,
   267→					StoragePath: vm.SubPath,
   268→					ReadOnly:    vm.ReadOnly,
   269→				})
   270→			}
   271→		}
   272→	}
   273→
   274→	// 提取 GPU 信息
   275→	gpu := "0"
   276→	gpuName := ""
   277→	if len(deployment.Spec.Template.Spec.Containers) > 0 {
   278→		container := deployment.Spec.Template.Spec.Containers[0]
   279→		if gpuResource, exists := container.Resources.Requests["hygon.com/dcu"]; exists {
   280→			gpu = gpuResource.String()
   281→			gpuName = "hygon.com/dcu"
   282→		} else if gpuResource, exists := container.Resources.Requests["nvidia.com/gpu"]; exists {
   283→			gpu = gpuResource.String()
   284→			gpuName = "nvidia.com/gpu"
   285→		}
   286→	}
   287→
   288→	// 获取 WebIDE 类型
   289→	webIDE := GetWebIDEType(deployment)
   290→
   291→	// 构建响应
   292→	response := &devmachinemodel.GetDevmachineResponse{
   293→		Devmachine: devmachinemodel.Devmachine{
   294→			Namespace:   deployment.Namespace,
   295→			Name:        deployment.Name,
   296→			QueueName:   deployment.Spec.Template.Annotations[volcanoQueueName],
   297→			ImageName:   deployment.Spec.Template.Spec.Containers[0].Image,
   298→			CPU:         deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Cpu().String(),
   299→			Memory:      deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Memory().String(),
   300→			GPU:         gpu,
   301→			GPUName:     gpuName,
   302→			WebIDE:      webIDE,
   303→			WebUrl:      fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(namespace, name)),
   304→			Storage:     storage,
   305→			Annotations: deployment.Annotations,
   306→			Labels:      deployment.Labels,
   307→			Status:      getStatusFromDeployment(deployment),
   308→		},
   309→	}
   310→
   311→	return response, nil
   312→}
