   124→// buildSharedPV 构建共享 PersistentVolume
   125→// 使用集群级别共享 PV，ReclaimPolicy 为 Retain（区别于旧的 Delete）
   126→func buildSharedPV(name, subPath string, readOnly bool) *corev1.PersistentVolume {
   127→	configMutex.RLock()
   128→	defer configMutex.RUnlock()
   129→
   130→	accessMode := corev1.ReadWriteMany
   131→	if readOnly {
   132→		accessMode = corev1.ReadOnlyMany
   133→	}
   134→
   135→	volumeMode := corev1.PersistentVolumeFilesystem
   136→	pv := &corev1.PersistentVolume{
   137→		ObjectMeta: metav1.ObjectMeta{
   138→			Name: name,
   139→		},
   140→		Spec: corev1.PersistentVolumeSpec{
   141→			Capacity: corev1.ResourceList{
   142→				corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
   143→			},
   144→			VolumeMode:  &volumeMode,
   145→			AccessModes: []corev1.PersistentVolumeAccessMode{accessMode},
   146→			PersistentVolumeReclaimPolicy: corev1.PersistentVolumeReclaimRetain,
   147→			PersistentVolumeSource: corev1.PersistentVolumeSource{
   148→				CSI: &corev1.CSIPersistentVolumeSource{
   149→					Driver: csiConfig.Driver,
   150→					FSType: "juicefs",
   151→					NodePublishSecretRef: &corev1.SecretReference{
   152→						Name:      csiConfig.SecretName,
   153→						Namespace: csiConfig.SecretNamespace,
   154→					},
   155→					VolumeHandle:     name,
   156→					VolumeAttributes: map[string]string{},
   157→				},
   158→			},
   159→		},
   160→	}
   161→
   162→	if csiConfig.MountOptions != nil {
   163→		pv.Spec.MountOptions = csiConfig.MountOptions
   164→	}
   165→	for k, v := range csiConfig.Parameters {
   166→		pv.Spec.CSI.VolumeAttributes[k] = v
   167→	}
   168→	if subPath != "" {
   169→		pv.Spec.CSI.VolumeAttributes["subPath"] = subPath
   170→	}
   171→
   172→	return pv
   173→}
