        _, err := tmpFile.WriteString(configContent)
        Expect(err).NotTo(HaveOccurred())
        tmpFile.Close()

        cfg, err := Load(configPath)
        Expect(err).NotTo(HaveOccurred())

        Expect(cfg.SharedStorage.RWPV.Name).To(Equal("shared-rw-pv"))
        Expect(cfg.SharedStorage.ROPV.Name).To(Equal("shared-ro-pv"))
        Expect(cfg.SharedStorage.RWPV.SubPath).To(Equal(""))
        Expect(cfg.SharedStorage.ROPV.SubPath).To(Equal(""))
    })

    It("should load custom PV names from config", func() {
        configContent := `server:
  mode: debug
sharedStorage:
  rwPV:
    name: "custom-rw-pv"
    subPath: "custom/rw/path"
  roPV:
    name: "custom-ro-pv"
    subPath: "custom/ro/path"
`
        _, err := tmpFile.WriteString(configContent)
        Expect(err).NotTo(HaveOccurred())
        tmpFile.Close()

        cfg, err := Load(configPath)
        Expect(err).NotTo(HaveOccurred())

        Expect(cfg.SharedStorage.RWPV.Name).To(Equal("custom-rw-pv"))
        Expect(cfg.SharedStorage.RWPV.SubPath).To(Equal("custom/rw/path"))
        Expect(cfg.SharedStorage.ROPV.Name).To(Equal("custom-ro-pv"))
        Expect(cfg.SharedStorage.ROPV.SubPath).To(Equal("custom/ro/path"))
    })
})
