   435→// ensureSharedPVs 服务启动时检查并创建集群共享 PV（如不存在则自动创建）
   436→func (s *service) ensureSharedPVs(ctx context.Context) error {
   437→	pvConfigs := []struct {
   438→		cfg      config.SharedPVConfig
   439→		readOnly bool
   440→	}{
   441→		{s.config.SharedStorage.RWPV, false},
   442→		{s.config.SharedStorage.ROPV, true},
   443→	}
   444→
   445→	for _, item := range pvConfigs {
   446→		if item.cfg.Name == "" {
   447→			continue
   448→		}
   449→		exists, err := s.k8sClient.PVExists(ctx, item.cfg.Name)
   450→		if err != nil {
   451→			return fmt.Errorf("check shared PV %s: %w", item.cfg.Name, err)
   452→		}
   453→		if !exists {
   454→			log.Printf("[startup] shared PV %s not found, creating...", item.cfg.Name)
   455→			pv, err := buildSharedPV(item.cfg.Name, item.cfg.SubPath, item.readOnly)
   456→			if err != nil {
   457→				return fmt.Errorf("build shared PV %s: %w", item.cfg.Name, err)
   458→			}
   459→			if err := s.k8sClient.CreatePV(ctx, pv); err != nil {
   460→				return fmt.Errorf("create shared PV %s: %w", item.cfg.Name, err)
   461→			}
   462→		}
   463→	}
   464→	return nil
   465→}
