   492→// ensurePVCExists 检查 PVC 是否存在，不存在则创建
   493→func (s *service) ensurePVCExists(ctx context.Context, namespace, pvcName, pvName string, readOnly bool) error {
   494→	exists, err := s.k8sClient.PVCExists(ctx, namespace, pvcName)
   495→	if err != nil {
   496→		return fmt.Errorf("check PVC %s/%s: %w", namespace, pvcName, err)
   497→	}
   498→	if !exists {
   499→		log.Printf("[compat] shared PVC %s not found in namespace %s, creating...", pvcName, namespace)
   500→		return s.k8sClient.CreatePVC(ctx, buildSharedPVC(namespace, pvcName, pvName, readOnly))
   501→	}
   502→	return nil
   503→}
