		Context("when namespace creation succeeds", func() {
			It("should create shared RW and RO PVCs in the new namespace", func() {
				k8sMock.EXPECT().CreateNamespace(gomock.Any(), "new-ns").Return(nil)
				k8sMock.EXPECT().CreatePVC(gomock.Any(), gomock.Any()).Return(nil).Times(2)

				resp, err := service.CreateNamespace(context.Background(), &devmachinemodel.CreateNamespaceRequest{
					Namespace: "new-ns",
				})
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Message).To(ContainSubstring("new-ns"))
			})
