	Describe("GetDevmachine", func() {
		buildTestDeployment := func(vmounts []corev1.VolumeMount) *appsv1.Deployment {
			return &appsv1.Deployment{
				ObjectMeta: metav1.ObjectMeta{
					Name:        "test-dm",
					Namespace:   "test-ns",
					Labels:      map[string]string{},
					Annotations: map[string]string{},
				},
				Spec: appsv1.DeploymentSpec{
					Template: corev1.PodTemplateSpec{
						ObjectMeta: metav1.ObjectMeta{
							Annotations: map[string]string{volcanoQueueName: ""},
						},
						Spec: corev1.PodSpec{
							Containers: []corev1.Container{
								{
									Image:        "registry/image:latest",
									VolumeMounts: vmounts,
									Resources:    corev1.ResourceRequirements{},
								},
							},
						},
					},
				},
			}
		}

		Context("when devmachine has both RW and RO shared storage mounts", func() {
			It("should read storage list from volumeMounts using volume name and subPath", func() {
				vmounts := []corev1.VolumeMount{
					{Name: devVolumeName, MountPath: "/opt/dev"},
					{Name: SharedRWVolumeName, MountPath: "/workspace/data", SubPath: "user/data", ReadOnly: false},
					{Name: SharedROVolumeName, MountPath: "/models", SubPath: "shared/models", ReadOnly: true},
				}
				k8sMock.EXPECT().GetDeployment(gomock.Any(), "test-ns", "test-dm").Return(buildTestDeployment(vmounts), nil)
				k8sMock.EXPECT().GetService(gomock.Any(), "test-ns", "test-dm"+serviceSuffix).Return(&corev1.Service{}, nil)
				k8sMock.EXPECT().GetIngress(gomock.Any(), "test-ns", "test-dm"+ingressSuffix).Return(&networkingv1.Ingress{}, nil)

				resp, err := service.GetDevmachine(context.Background(), "test-ns", "test-dm")
				Expect(err).NotTo(HaveOccurred())
				Expect(resp.Devmachine.Storage).To(HaveLen(2))

				Expect(resp.Devmachine.Storage[0].MountPath).To(Equal("/workspace/data"))
