				Expect(volumes).To(HaveLen(1))

				// 验证 dev-volume emptyDir
				Expect(volumes[0].Name).To(Equal(devVolumeName))
				Expect(volumes[0].EmptyDir).NotTo(BeNil())
			})
		})

		Context("when WebIDE is Jupyter", func() {
			It("should create 2 volumes including bootstrap-jupyter", func() {
				volumes := buildVolumes(devmachinemodel.WebIDEJupyter)

				Expect(volumes).To(HaveLen(2))

				// 验证基础卷
				Expect(volumes[0].Name).To(Equal(devVolumeName))

				// 验证 Jupyter 专属卷
				Expect(volumes[1].Name).To(Equal(bootstrapJupyterVolumeName))
				Expect(volumes[1].EmptyDir).NotTo(BeNil())
			})
		})
	})

	Describe("buildInitEnv", func() {
		Context("when WebIDE is VSCode", func() {
			It("should set DEV_MODE to vscode", func() {
				envVars := buildInitEnv(devmachinemodel.WebIDEVSCode)

				Expect(envVars).To(HaveLen(1))
				Expect(envVars[0].Name).To(Equal("DEV_MODE"))
				Expect(envVars[0].Value).To(Equal("vscode"))
			})
		})

		Context("when WebIDE is Jupyter", func() {
			It("should set DEV_MODE to jupyter", func() {
				envVars := buildInitEnv(devmachinemodel.WebIDEJupyter)

				Expect(envVars).To(HaveLen(1))
				Expect(envVars[0].Name).To(Equal("DEV_MODE"))
				Expect(envVars[0].Value).To(Equal("jupyter"))
			})
		})
	})

	Describe("buildInitCommand", func() {
		It("should use script mode", func() {
			cmd := buildInitCommand()

			Expect(cmd).To(HaveLen(3))
			Expect(cmd[0]).To(Equal("sh"))
			Expect(cmd[1]).To(Equal("-c"))
			Expect(cmd[2]).To(ContainSubstring("/dev-bootstrap/entrypoint.sh"))
		})
	})

	Describe("buildInitVolumeMounts", func() {
		Context("when WebIDE is VSCode", func() {
			It("should mount dev-volume", func() {
				mounts := buildInitVolumeMounts(devmachinemodel.WebIDEVSCode)

				Expect(mounts).To(HaveLen(1))
				Expect(mounts[0].Name).To(Equal(devVolumeName))
				Expect(mounts[0].MountPath).To(Equal("/opt/dev"))
			})
		})

		Context("when WebIDE is Jupyter", func() {
			It("should mount dev-volume and bootstrap-jupyter", func() {
				mounts := buildInitVolumeMounts(devmachinemodel.WebIDEJupyter)

				Expect(mounts).To(HaveLen(2))
				Expect(mounts[0].Name).To(Equal(devVolumeName))
				Expect(mounts[1].Name).To(Equal(bootstrapJupyterVolumeName))
				Expect(mounts[1].MountPath).To(Equal("/mnt/"))
			})
		})
	})

	Describe("buildJupyterEnv", func() {
		It("should include all required environment variables", func() {
			envVars := buildJupyterEnv()

			Expect(envVars).To(HaveLen(4))

			// 验证 DEV_MODE
			Expect(envVars[0].Name).To(Equal("DEV_MODE"))
			Expect(envVars[0].Value).To(Equal("jupyter"))

			// 验证 WORKDIR
			Expect(envVars[1].Name).To(Equal("WORKDIR"))
			Expect(envVars[1].Value).To(Equal("tap-edu"))

			// 验证 POD_NAMESPACE
			Expect(envVars[2].Name).To(Equal("POD_NAMESPACE"))
			Expect(envVars[2].ValueFrom).NotTo(BeNil())
			Expect(envVars[2].ValueFrom.FieldRef.FieldPath).To(Equal("metadata.namespace"))

			// 验证 DEPLOYMENT_NAME
			Expect(envVars[3].Name).To(Equal("DEPLOYMENT_NAME"))
			Expect(envVars[3].ValueFrom).NotTo(BeNil())
			Expect(envVars[3].ValueFrom.FieldRef.FieldPath).To(Equal("metadata.labels['app']"))
		})
	})

	Describe("buildVSCodeEnv", func() {
		It("should include all required environment variables", func() {
			envVars := buildVSCodeEnv()

			Expect(envVars).To(HaveLen(4))

			// 验证 DEV_MODE
			Expect(envVars[0].Name).To(Equal("DEV_MODE"))
			Expect(envVars[0].Value).To(Equal("vscode"))

			// 验证其他环境变量与 Jupyter 一致
			Expect(envVars[1].Name).To(Equal("WORKDIR"))
			Expect(envVars[2].Name).To(Equal("POD_NAMESPACE"))
