			Expect(mounts[0].Name).To(Equal(devVolumeName))
			Expect(mounts[0].MountPath).To(Equal("/opt/dev"))

			// 验证 bootstrap-jupyter
			Expect(mounts[1].Name).To(Equal(bootstrapJupyterVolumeName))
			Expect(mounts[1].MountPath).To(Equal("/dev-bootstrap/tools/jupyter"))
			Expect(mounts[1].SubPath).To(Equal("jupyter"))

		})
	})

	Describe("buildVSCodeVolumeMounts", func() {
		It("should mount all required volumes", func() {
			mounts := buildVSCodeVolumeMounts()

			Expect(mounts).To(HaveLen(1))

			// 验证 dev-volume
			Expect(mounts[0].Name).To(Equal(devVolumeName))
			Expect(mounts[0].MountPath).To(Equal("/opt/dev"))
		})
	})

	Describe("buildInitContainerCommand", func() {
