				Expect(podSpec.Containers[0].Name).To(Equal("jupyter"))
			})
		})

		Context("when WebIDE is not specified", func() {
			It("should default to Jupyter", func() {
				request.WebIDE = ""
				podSpec := buildPodSpec(request, "mock-image:latest")

				// 应该使用 Jupyter 配置（2个卷）
				Expect(podSpec.Volumes).To(HaveLen(2))
				Expect(podSpec.Containers[0].Name).To(Equal("jupyter"))
			})
		})

		Context("when VSCode with one RW storage entry", func() {
			It("should append shared-rw-volume giving 2 total volumes", func() {
				request.WebIDE = devmachinemodel.WebIDEVSCode
				request.Storage = []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/data", ReadOnly: false},
				}
				podSpec := buildPodSpec(request, "mock-image:latest")

				// 1 基础卷 (dev-volume) + 1 共享RW卷 = 2
				Expect(podSpec.Volumes).To(HaveLen(2))
				volumeNames := make([]string, len(podSpec.Volumes))
				for i, v := range podSpec.Volumes {
					volumeNames[i] = v.Name
				}
				Expect(volumeNames).To(ContainElement(devVolumeName))
				Expect(volumeNames).To(ContainElement(SharedRWVolumeName))
			})
		})

		Context("when Jupyter with RW and RO storage entries", func() {
			It("should append both shared volumes giving 4 total volumes", func() {
				request.WebIDE = devmachinemodel.WebIDEJupyter
				request.Storage = []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/data", ReadOnly: false},
					{StoragePath: "shared/models", MountPath: "/models", ReadOnly: true},
				}
				podSpec := buildPodSpec(request, "mock-image:latest")

				// 2 基础卷 + 2 共享卷 = 4
				Expect(podSpec.Volumes).To(HaveLen(4))
			})
		})

		Context("when Jupyter with multiple RW storage entries", func() {
			It("should deduplicate shared volumes giving 3 total volumes", func() {
				request.WebIDE = devmachinemodel.WebIDEJupyter
				request.Storage = []devmachinemodel.Storage{
					{StoragePath: "project/a", MountPath: "/a", ReadOnly: false},
					{StoragePath: "project/b", MountPath: "/b", ReadOnly: false},
					{StoragePath: "project/c", MountPath: "/c", ReadOnly: false},
				}
				podSpec := buildPodSpec(request, "mock-image:latest")

				// 2 基础卷 + 1 共享RW卷（去重）= 3，而非5
				Expect(podSpec.Volumes).To(HaveLen(3))
				volumeNames := make([]string, len(podSpec.Volumes))
				for i, v := range podSpec.Volumes {
					volumeNames[i] = v.Name
				}
				Expect(volumeNames).To(ContainElement(SharedRWVolumeName))
				Expect(volumeNames).NotTo(ContainElement(SharedROVolumeName))
			})
		})

		Context("when Jupyter with multiple RW storage entries", func() {
			It("should create one volumeMount per storage entry each with its own subPath", func() {
				request.WebIDE = devmachinemodel.WebIDEJupyter
				request.Storage = []devmachinemodel.Storage{
					{StoragePath: "project/a", MountPath: "/a", ReadOnly: false},
					{StoragePath: "project/b", MountPath: "/b", ReadOnly: false},
				}
				podSpec := buildPodSpec(request, "mock-image:latest")

				// 找到容器的所有 shared-rw-volume 挂载
				container := podSpec.Containers[0]
				var sharedMounts []corev1.VolumeMount
				for _, vm := range container.VolumeMounts {
					if vm.Name == SharedRWVolumeName {
						sharedMounts = append(sharedMounts, vm)
					}
				}
				Expect(sharedMounts).To(HaveLen(2))
				subPaths := []string{sharedMounts[0].SubPath, sharedMounts[1].SubPath}
				Expect(subPaths).To(ContainElements("project/a", "project/b"))
			})
		})
	})
})

